/**
 * @summary Submit feedback for an analysis
 */
export const createFeedbackBodyRatingMax = 5;

export const createFeedbackBodyAccuracyMax = 5;

export const CreateFeedbackBody = zod.object({
  analysisId: zod.number().describe("ID of the analysis being reviewed"),
  rating: zod
    .number()
    .min(1)
    .max(createFeedbackBodyRatingMax)
    .describe("1-5 star rating"),
  accuracy: zod
    .number()
    .min(1)
    .max(createFeedbackBodyAccuracyMax)
    .optional()
    .describe("How accurate was the analysis? 1-5"),
  comment: zod.string().optional().describe("Free text feedback"),
  helpful: zod.boolean().optional().describe("Was this analysis helpful?"),
});

export const CreateFeedbackResponse = zod.object({
  id: zod.number(),
  analysisId: zod.number(),
  situationSnippet: zod.string().optional(),
  rating: zod.number(),
  accuracy: zod.number().optional(),
  comment: zod.string().optional(),
  helpful: zod.boolean().optional(),
  createdAt: zod.string(),
});

